import React, { createContext, useContext, useState, useEffect } from 'react';

const WalletContext = createContext();

export const useWallet = () => {
  const context = useContext(WalletContext);
  if (!context) {
    throw new Error('useWallet must be used within a WalletProvider');
  }
  return context;
};

export const WalletProvider = ({ children }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [walletAddress, setWalletAddress] = useState('');
  const [isConnecting, setIsConnecting] = useState(false);
  const [error, setError] = useState('');
  
  // User profile data
  const [userProfile, setUserProfile] = useState({
    displayName: '',
    bio: '',
    avatar: '',
    location: '',
    website: '',
    twitter: ''
  });

  // Mock NFTs owned by user
  const [ownedNFTs] = useState([
    {
      id: '1',
      name: 'DeChat Genesis',
      collection: 'DeChat Official',
      tokenId: '001',
      image: 'https://via.placeholder.com/150/3b82f6/ffffff?text=NFT1'
    },
    {
      id: '2',
      name: 'Crypto Punk #1234',
      collection: 'CryptoPunks',
      tokenId: '1234',
      image: 'https://via.placeholder.com/150/ef4444/ffffff?text=NFT2'
    }
  ]);

  const connectWallet = async () => {
    setIsConnecting(true);
    setError('');
    
    try {
      // Mock MetaMask connection
      if (typeof window.ethereum !== 'undefined') {
        // Simulate connection delay
        await new Promise(resolve => setTimeout(resolve, 1000));
        
        // Mock wallet address
        const mockAddress = '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9';
        setWalletAddress(mockAddress);
        setIsConnected(true);
      } else {
        throw new Error('MetaMask not detected. Please install MetaMask to continue.');
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setIsConnecting(false);
    }
  };

  const disconnectWallet = () => {
    setIsConnected(false);
    setWalletAddress('');
    setError('');
  };

  const updateProfile = (profileData) => {
    setUserProfile(prev => ({ ...prev, ...profileData }));
  };

  const value = {
    isConnected,
    walletAddress,
    isConnecting,
    error,
    ownedNFTs,
    userProfile,
    connectWallet,
    disconnectWallet,
    updateProfile
  };

  return (
    <WalletContext.Provider value={value}>
      {children}
    </WalletContext.Provider>
  );
};
